from PIL import Imageimg1 = Image.open("/Users/grnho/Desktop/image-processing-fundamentals/data/test_image.jpg")print(img1.format)print(img1.mode)#RGBsmall_img = img1.resize((200, 300))small_img.save("/Users/grnho/Desktop/image-processing-fundamentals/data/test_image_small.jpg")#resized it but did not keep the aspect ratio#resized does not have size limit but thumbnail has the max that cannot exceed the org size"""img1.thumbnail((200,300))img1.save("/Users/grnho/Desktop/image-processing-fundamentals/data/tmbnail_image.jpg")"""print(img1.size)cropped_img = img1.crop((0,0,300,300))cropped_img.save("/Users/grnho/Desktop/image-processing-fundamentals/data/cropped_image.jpg")img2 = Image.open("/Users/grnho/Desktop/image-processing-fundamentals/data/monkey.jpg")print(img2.size)img2.thumbnail((150, 200))print(img2.size)img1_copy = img1.copy()img1_copy.paste(img2, (50, 50))img1_copy.save("/Users/grnho/Desktop/image-processing-fundamentals/data/pasted_img.jpg")img45 = img1.rotate(45, expand = True)img45.save("/Users/grnho/Desktop/image-processing-fundamentals/data/rotate45.jpg")img_flipLR = img2.transpose(Image.FLIP_LEFT_RIGHT)img_flipLR.save("/Users/grnho/Desktop/image-processing-fundamentals/data/FlippedLR.jpg")img_flipTB = img2.transpose(Image.FLIP_TOP_BOTTOM)img_flipTB.save("/Users/grnho/Desktop/image-processing-fundamentals/data/FlippedTB.jpg")grey_img = img2.convert("L")grey_img.save("/Users/grnho/Desktop/image-processing-fundamentals/data/grey_monkey.jpg")